import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost' | 'icon';
  size?: 'sm' | 'md' | 'lg';
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  className = '', 
  ...props 
}) => {
  // iOS Button Philosophy: Physical interactions, no sharp edges.
  const baseStyles = "inline-flex items-center justify-center font-medium transition-all duration-200 active:scale-[0.98] disabled:opacity-50 disabled:active:scale-100 select-none";

  const variants = {
    // Primary: Deep Forest Green background, White text
    primary: "bg-[#3A5C34] text-white rounded-full hover:bg-[#2d4a29] shadow-sm",

    // Secondary: Soft Pink background, Deep Burgundy text
    secondary: "bg-[#FCCAE2] text-[#5F2427] rounded-full hover:bg-[#fbbad6]",

    // Ghost: Deep Green text, subtle pink hover
    ghost: "text-[#3A5C34] hover:bg-[#FCCAE2]/20 rounded-lg",

    // Icon: Deep Green text, pink hover
    icon: "text-[#3A5C34] hover:bg-[#FCCAE2]/30 rounded-full p-2"
  };

  const sizes = {
    sm: "px-3 py-1 text-[13px] leading-4",
    md: "px-5 py-2 text-[15px] leading-5",
    lg: "px-6 py-3 text-[17px] leading-6"
  };

  const finalClass = `${baseStyles} ${variants[variant]} ${variant === 'icon' ? '' : sizes[size]} ${className}`;

  return (
    <button className={finalClass} {...props}>
      {children}
    </button>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { CardData, CardType } from '../../types';
import { Maximize2, Minimize2 } from 'lucide-react';

interface BaseCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string, options?: { toggle?: boolean; keepOthers?: boolean }) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  onResize: (id: string, geometry: { width: number; height: number; x?: number; y?: number }) => void;
  zoomScale: number;
  children: React.ReactNode;
  title?: string;
  accentColor?: string;
  icon?: React.ReactNode;
  variant?: 'default' | 'minimal' | 'sticky'; 
  className?: string;
}

export const BaseCard: React.FC<BaseCardProps> = ({
  card,
  isSelected,
  onSelect,
  onMove,
  onDelete, 
  onResize,
  zoomScale,
  children,
  title,
  icon,
  variant = 'default',
  className = ''
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const hasMovedRef = useRef(false);

  const isFixedLayout = [CardType.GRID_PLANNER, CardType.ANALYTICS, CardType.PERSONA].includes(card.type);

  const handleMouseDown = (e: React.MouseEvent) => {
    // Allow Middle Click to bubble to Canvas for Panning
    if (e.button === 1 || isFullscreen) return;

    // Stop propagation so we don't trigger Canvas Marquee or Deselect
    e.stopPropagation();

    // Selection Logic
    if (e.shiftKey) {
        // Shift + Click: Toggle selection
        onSelect(card.id, { toggle: true });
    } else {
        if (!isSelected) {
            // New selection: Clear others immediately
            onSelect(card.id, { keepOthers: false });
        } else {
            // Already selected: Keep group selected (might be start of a group drag)
            onSelect(card.id, { keepOthers: true }); 
        }
    }

    const target = e.target as HTMLElement;
    const isInteractive = 
      target.tagName === 'INPUT' || 
      target.tagName === 'TEXTAREA' || 
      target.isContentEditable ||
      target.tagName === 'BUTTON' || 
      target.closest('button') ||
      target.closest('.no-drag');

    if (!isInteractive) {
      setIsDragging(true);
      hasMovedRef.current = false;
      dragStartRef.current = { x: e.clientX, y: e.clientY };
    }
  };

  const handleResizeStart = (e: React.MouseEvent, corner: string) => {
    e.stopPropagation();
    e.preventDefault();

    const startX = e.clientX;
    const startY = e.clientY;
    const startBounds = { x: card.x, y: card.y, width: card.width, height: card.height };

    const handleMouseMove = (ev: MouseEvent) => {
        const scale = zoomScale;
        const dx = (ev.clientX - startX) / scale;
        const dy = (ev.clientY - startY) / scale;

        let newBounds = { ...startBounds };

        // Width & Height
        if (corner.includes('e')) newBounds.width = Math.max(100, startBounds.width + dx);
        if (corner.includes('s')) newBounds.height = Math.max(100, startBounds.height + dy);

        // Negative axis resizing (Left/Top) requires moving X/Y
        if (corner.includes('w')) {
            const maxDx = startBounds.width - 100;
            const effectiveDx = Math.min(maxDx, dx);
            newBounds.width = startBounds.width - effectiveDx;
            newBounds.x = startBounds.x + effectiveDx;
        }
        if (corner.includes('n')) {
            const maxDy = startBounds.height - 100;
            const effectiveDy = Math.min(maxDy, dy);
            newBounds.height = startBounds.height - effectiveDy;
            newBounds.y = startBounds.y + effectiveDy;
        }

        onResize(card.id, newBounds);
    };

    const handleMouseUp = () => {
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('mouseup', handleMouseUp);
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;

      const dx = (e.clientX - dragStartRef.current.x) / zoomScale;
      const dy = (e.clientY - dragStartRef.current.y) / zoomScale;

      if (Math.abs(dx) > 1 || Math.abs(dy) > 1) {
          hasMovedRef.current = true;
      }

      onMove(card.id, card.x + dx, card.y + dy);
      dragStartRef.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseUp = (e: MouseEvent) => {
      if (isDragging) {
        // If we didn't drag, didn't shift-click, and are already selected...
        // This is a "Click-Through" on a group member. Now we deselect the others.
        if (!hasMovedRef.current && isSelected && !e.shiftKey) {
            onSelect(card.id, { keepOthers: false });
        }
        setIsDragging(false);
      }
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, card.id, card.x, card.y, onMove, zoomScale, isSelected, onSelect]);

  const toggleFullscreen = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsFullscreen(!isFullscreen);
  };

  const getSelectionStyles = () => {
    if (isFullscreen) return 'fixed inset-0 z-[9999] w-full h-full rounded-none bg-white overflow-auto';

    // Variant-based styling
    if (variant === 'minimal') {
      return `absolute select-none ${isSelected ? '' : 'hover:ring-1 hover:ring-[#3A5C34]/30'}`;
    }

    if (variant === 'sticky') {
      return `absolute flex flex-col transition-shadow duration-200 cursor-grab active:cursor-grabbing ${isSelected ? 'shadow-2xl z-50' : 'shadow-md hover:shadow-lg z-10'}`;
    }

    // Default Cards
    // Using the Vibrant Yellow for hover rings to make it feel active and creative
    const colors = {
      [CardType.POST]: { hover: 'hover:ring-[#FFD753]' },
      [CardType.STRATEGY_AI]: { hover: 'hover:ring-[#FFD753]' },
      [CardType.ANALYTICS]: { hover: 'hover:ring-[#FFD753]' },
      [CardType.PERSONA]: { hover: 'hover:ring-[#FFD753]' },
      [CardType.GRID_PLANNER]: { hover: 'hover:ring-[#FFD753]' },
      [CardType.PINTEREST]: { hover: 'hover:ring-[#FFD753]' }
    }[card.type] || { hover: 'hover:ring-gray-300' };

    const base = "flex flex-col bg-white transition-all duration-300 ease-[cubic-bezier(0.2,0.8,0.2,1)] cursor-grab active:cursor-grabbing absolute";

    if (isSelected) {
      return `${base} shadow-[0_20px_40px_-12px_rgba(58,92,52,0.2)] z-50 scale-[1.005]`;
    } else {
      return `${base} shadow-[0_4px_12px_-4px_rgba(0,0,0,0.08)] z-10 hover:shadow-[0_12px_24px_-8px_rgba(0,0,0,0.1)] hover:ring-2 hover:ring-offset-0 ${colors.hover}`;
    }
  };

  const cardContent = (
    <div
      ref={containerRef}
      className={`${getSelectionStyles()} ${className}`}
      style={!isFullscreen ? {
        left: card.x,
        top: card.y,
        width: card.width,
        height: isFixedLayout ? card.height : 'auto', 
        minHeight: isFixedLayout ? undefined : card.height,
        borderRadius: variant === 'default' ? '24px' : undefined,
      } : {}}
      onMouseDown={handleMouseDown}
